const articleTerms = [
  'top 10',
  'top 100',
  'list',
  'article',
  'blog',
  'resource hub',
  'search',
  'category',
  'news',
  'careers',
  'jobs',
];

const competitorTerms = [
  'manufacturer',
  'manufacturing',
  'supplier',
  'factory',
  'wholesale',
  'wholesaler',
  'distributor',
];

const relevanceTerms = [
  'retail display',
  'display fixtures',
  'acrylic display',
  'merchandising',
  'signage',
  'custom displays',
  'store fixtures',
];

return $input.all().map((item) => {
  const data = item.json;

  const title = String(data.title || data.page_title || '').toLowerCase();
  const snippet = String(data.snippet || data.page_snippet || '').toLowerCase();
  const url = String(data.url || data.website || '').toLowerCase();
  const companyName = String(data.company_name || '').toLowerCase();

  const text = `${title} ${snippet} ${url} ${companyName}`;

  const matchedArticleTerms = articleTerms.filter((term) => text.includes(term));
  const matchedCompetitorTerms = competitorTerms.filter((term) => text.includes(term));
  const matchedRelevanceTerms = relevanceTerms.filter((term) => text.includes(term));

  let relevanceScore = 0;
  let candidateStatus = 'low_priority';
  let reviewNotes = '';

  // 最高优先级：明显非公司页面
  if (matchedArticleTerms.length > 0) {
    relevanceScore = Math.max(0, matchedRelevanceTerms.length * 8 - 10);
    candidateStatus = 'rejected';
    reviewNotes =
      `明显非公司内容：${matchedArticleTerms.join(', ')}。` +
      (matchedRelevanceTerms.length
        ? `业务相关关键词：${matchedRelevanceTerms.join(', ')}。`
        : '');
  } else {
    // 业务相关性加分
    relevanceScore += matchedRelevanceTerms.length * 10;

    // 有独立官网基础分
    if (url.startsWith('http')) {
      relevanceScore += 8;
    }

    // 第二优先级：同行 / 渠道 / 制造商
    if (matchedCompetitorTerms.length > 0) {
      relevanceScore = Math.max(relevanceScore, 25);
      candidateStatus = 'competitor_review';
      reviewNotes =
        `疑似竞争方、制造商或渠道商：${matchedCompetitorTerms.join(', ')}。` +
        (matchedRelevanceTerms.length
          ? `业务相关关键词：${matchedRelevanceTerms.join(', ')}。`
          : '建议人工确认是否存在采购、合作或渠道机会。');
    } else if (relevanceScore >= 35) {
      candidateStatus = 'review';
      reviewNotes =
        `疑似目标公司官网。业务相关关键词：${matchedRelevanceTerms.join(', ')}。`;
    } else {
      candidateStatus = 'low_priority';
      reviewNotes =
        matchedRelevanceTerms.length > 0
          ? `业务相关关键词较少：${matchedRelevanceTerms.join(', ')}，按低优先级保留。`
          : '信息不足，按低优先级保留。';
    }
  }

  return {
    json: {
      ...data,
      relevance_score: relevanceScore,
      candidate_status: candidateStatus,
      review_notes: reviewNotes,
      reviewed_at: new Date().toISOString(),
    },
  };
});
